import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, HttpResponse}
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.stream.Materializer
import scala.concurrent.{ExecutionContext, Future}
import scala.util.{Failure, Success}

case class Url(url: String)

object WebhookProxyService extends App {
  
  implicit val system: ActorSystem = ActorSystem()
  implicit val materializer: Materializer = Materializer(system)
  implicit val executionContext: ExecutionContext = system.dispatcher

  val route =
    path("fetch-content") {
      post {
        entity(as[String]) { url =>
          complete(fetchContent(url))
        }
      }
    }

  def fetchContent(url: String): Future[String] = {
    val responseFuture: Future[HttpResponse] = Http().singleRequest(HttpRequest(uri = url))

    responseFuture.flatMap { response =>
      Unmarshal(response.entity).to[String]
    }
  }

  val bindingFuture = Http().newServerAt("localhost", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(_) =>
      println("Server successfully started on localhost:8080")
    case Failure(exception) =>
      println(s"Failed to start a server, Reason: ${exception.getMessage}")
  }
}